import { useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./LeaveApply.css";

function LeaveApply() {
  const navigate = useNavigate();
  const { id } = useParams();

  const loggedInUser = JSON.parse(localStorage.getItem("loggedInUser"));
  const employees = JSON.parse(localStorage.getItem("employees")) || [];

  const currentEmployee = employees.find(
    (e) =>
      String(e?.id) === String(id) ||
      String(e?.empId) === String(id)
  );

  // Hooks MUST always be on top
  const [leaveType, setLeaveType] = useState("Sick Leave");
  const [fromDate, setFromDate] = useState("");
  const [toDate, setToDate] = useState("");
  const [reason, setReason] = useState("");

  const appliedDate = new Date().toISOString().split("T")[0];

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!fromDate || !toDate || !reason.trim()) {
      alert("Please fill all fields");
      return;
    }

    const leaveRequests =
      JSON.parse(localStorage.getItem("leaveRequests")) || [];

    const newLeave = {
      id: Date.now().toString(),
      empId: currentEmployee?.id || currentEmployee?.empId,
      empEmail: loggedInUser?.email,
      empName:
        currentEmployee?.name ||
        `${currentEmployee?.firstName || ""} ${currentEmployee?.lastName || ""}`.trim(),
      leaveType,
      fromDate,
      toDate,
      reason,
      appliedDate,
      status: "Pending",
    };

    leaveRequests.push(newLeave);
    localStorage.setItem("leaveRequests", JSON.stringify(leaveRequests));

    alert("Leave Applied Successfully");
    navigate("/dashboard/employee-details/leave-history");
  };

  return (
    <div className="leave-page-container">
      <div className="leave-card">

        {/* SAFE NOT FOUND UI */}
        {!currentEmployee ? (
          <h2 style={{ textAlign: "center" }}>Employee Not Found</h2>
        ) : (
          <>
            <h2 className="leave-title">Apply Leave</h2>

            <form onSubmit={handleSubmit} className="leave-form">
              <div className="row">
                <div>
                  <label>Employee ID</label>
                  <input
                    value={currentEmployee?.id || currentEmployee?.empId}
                    disabled
                  />
                </div>

                <div>
                  <label>Name</label>
                  <input
                    value={
                      currentEmployee?.name ||
                      `${currentEmployee?.firstName || ""} ${currentEmployee?.lastName || ""}`.trim()
                    }
                    disabled
                  />
                </div>
              </div>

              <div className="row">
                <div>
                  <label>Leave Type</label>
                  <select
                    value={leaveType}
                    onChange={(e) => setLeaveType(e.target.value)}
                  >
                    <option>Sick Leave</option>
                    <option>Casual Leave</option>
                    <option>Annual Leave</option>
                  </select>
                </div>

                <div>
                  <label>Applied Date</label>
                  <input value={appliedDate} disabled />
                </div>
              </div>

              <div className="row">
                <div>
                  <label>From Date</label>
                  <input
                    type="date"
                    value={fromDate}
                    onChange={(e) => setFromDate(e.target.value)}
                  />
                </div>

                <div>
                  <label>To Date</label>
                  <input
                    type="date"
                    value={toDate}
                    onChange={(e) => setToDate(e.target.value)}
                  />
                </div>
              </div>

              <div className="row-full">
                <label>Reason</label>
                <textarea
                  value={reason}
                  onChange={(e) => setReason(e.target.value)}
                  placeholder="Enter leave reason"
                ></textarea>
              </div>

              <div className="button-row">
                <button className="btn-submit" type="submit">
                  Submit Leave
                </button>

                <button
                  type="button"
                  className="btn-cancel"
                  onClick={() =>
                    navigate("/dashboard/employee-details/leave-history")
                  }
                >
                  Cancel
                </button>
              </div>
            </form>
          </>
        )}
      </div>
    </div>
  );
}

export default LeaveApply;
